  ('dietitian-moex-01108', 'dietitian', 'dietitian-moex-111-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '根據包裝食品營養標示應遵行事項，包裝食品之營養標示必須標示「碳水化合物、糖含量」，此處 之「糖含量」是指：', '["僅指單醣之含量", "特指雙醣之含量", "單醣加雙醣之總量", "包括單醣、雙醣與三醣之總和"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "0a9b393b0fe4", "answer_pdf_sha1": "91f5381dba79", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
